+const EXT4_POSIX_ACL_STORAGE_VERSION: u32 = 0x0001;
+const POSIX_ACL_XATTR_VERSION: u32 = 0x0002;
+const POSIX_ACL_TAG_USER: u16 = 0x0002;
+const POSIX_ACL_TAG_GROUP: u16 = 0x0008;
+const POSIX_ACL_UNDEFINED_ID: u32 = u32::MAX;
